sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	//Run on change and on load, even if value is empty.

	var gaValidateValue, intervalValidatingMsg;
	var isAdvanced = g_form.getValue('advanced') === 'true';

	//Unable to validate scripted values client-side.
	if (isAdvanced) {
		return;
	}

	intervalValidatingMsg = showValidatingMsg();

	gaValidateValue = new GlideAjax('x_taniu_tan_core.ConfiguredSensorAJAX');
	gaValidateValue.addParam('sysparm_name', 'checkConfiguredSensorParamValue');
	gaValidateValue.addParam('sensor_param_sys_id', g_form.getValue('sensor_parameter'));
	gaValidateValue.addParam('configured_param_value', g_form.getValue('value'));
	gaValidateValue.getXMLAnswer(function (answer) {
		var isValid, helpString;
		stopValidatingMsg(intervalValidatingMsg);

		answer = JSON.parse(answer);
		isValid = answer.valid;
		helpString = answer.help_string;

		//Remove any existing field messages
		g_form.hideFieldMsg('value', true);

		//If provided value is not valid, show an error message on the field.
		if (!isValid) {
			g_form.hideFieldMsg('value', true);

			if (helpString) {
				g_form.showFieldMsg('value', helpString, 'error');
			} else {
				g_form.showFieldMsg('value', 'Configured Parameter value appears to be invalid. You can save the form anyway, but be sure to test this to make sure that it works.', 'warning');
			}
			g_form.flash('value', 'yellow', -2);
		}
	});

	function showValidatingMsg() {
		var intervalDots = {'count' : 1};
		var intervalValidatingMsg = setInterval(function () {
			var i;
			var validatingMessage = 'Validating';

			if (intervalDots.count >= 3) {
				intervalDots.count = 1;
			} else {
				intervalDots.count++;
			}

			for (i = 0; i < intervalDots.count; i++) {
				validatingMessage += '.';
			}

			g_form.hideFieldMsg('value', true);
			g_form.showFieldMsg('value', validatingMessage, 'info');
		}, 170, intervalDots);
		return intervalValidatingMsg;
	}

	function stopValidatingMsg(intervalValidatingMsg) {
		clearInterval(intervalValidatingMsg);
	}
}
